// WS200/WS300 Dynamic Vibration — Lite Summary
// Topic: dyn/vib/notify/lite
// Payload has nested "Reading" object

const reading = msg.payload.Reading;
if (!reading) {
    node.warn("dyn/vib/notify/lite: Missing 'Reading' object");
    return null;
}

msg.measurement = "vibration";
msg.tags = {
    sensor_id: reading.Serial ? reading.Serial.toString() : "unknown",
    gateway_sn: "43250372",
    model: (reading.Serial ? (reading.Serial.toString().startsWith("2225") ? "WS300" : reading.Serial.toString().startsWith("1125") ? "WS200" : "WS_DYNAMIC") : "WS_DYNAMIC"),
    data_type: "lite",
    site: "Cement_Plant"
};
msg.timestamp = new Date(reading.Time + "Z").getTime();
msg.payload = {
    x_pk: reading.Xpk || 0,
    x_pp: reading.Xpp || 0,
    x_rms: reading.Xrms || 0,
    y_pk: reading.Ypk || 0,
    y_pp: reading.Ypp || 0,
    y_rms: reading.Yrms || 0,
    z_pk: reading.Zpk || 0,
    z_pp: reading.Zpp || 0,
    z_rms: reading.Zrms || 0,
    vel_x_pk: reading.VelXpk || 0,
    vel_x_pp: reading.VelXpp || 0,
    vel_x_rms: reading.VelXrms || 0,
    vel_y_pk: reading.VelYpk || 0,
    vel_y_pp: reading.VelYpp || 0,
    vel_y_rms: reading.VelYrms || 0,
    vel_z_pk: reading.VelZpk || 0,
    vel_z_pp: reading.VelZpp || 0,
    vel_z_rms: reading.VelZrms || 0,
    reading_id: reading.ID || 0
};

msg.payload = [msg.payload, msg.tags];
return msg;

// WS200/WS300 Dynamic Vibration — Full FFT Spectrum
// Topic: dyn/vib/notify (without /lite)

const isAlert = msg.payload.IsAlert;
const reading = msg.payload.Reading;
if (!reading) {
    node.warn("dyn/vib/notify: Missing 'Reading' object");
    return null;
}

msg.measurement = "vibration_fft";
msg.tags = {
    sensor_id: reading.Serial ? reading.Serial.toString() : "unknown",
    gateway_sn: "43250372",
    model: (reading.Serial ? (reading.Serial.toString().startsWith("2225") ? "WS300" : reading.Serial.toString().startsWith("1125") ? "WS200" : "WS_DYNAMIC") : "WS_DYNAMIC"),
    data_type: "fft",
    site: "Cement_Plant"
};
msg.timestamp = new Date(reading.Time + "Z").getTime();
msg.payload = {
    samples: reading.Samples || 0,
    sampling_freq: reading.Fs || 0,
    read_period: reading.ReadPeriod || 0,
    reading_id: reading.ID || 0,
    is_alert: isAlert ? 1 : 0
};

msg.payload = [msg.payload, msg.tags];
return msg;

// WS100 Process Control Sensor
// Topic: proc/reading/notify

const data = msg.payload;
if (!data.Serial) {
    node.warn("proc/reading/notify: Missing 'Serial'");
    return null;
}

msg.measurement = "vibration";
msg.tags = {
    sensor_id: data.Serial.toString(),
    gateway_sn: "43250372",
    model: "WS100",
    data_type: "process",
    site: "Cement_Plant"
};
msg.timestamp = new Date(data.Time + "Z").getTime();
msg.payload = {
    x_rms: data.Xrms || 0,
    y_rms: data.Yrms || 0,
    z_rms: data.Zrms || 0,
    temperature: data.Temp || 0,
    battery: data.Batt || 0
};

msg.payload = [msg.payload, msg.tags];
return msg;

// Battery Notification
// Topic: dyn/batt/notify

const data = msg.payload;
if (!data.Serial) {
    node.warn("dyn/batt/notify: Missing 'Serial'");
    return null;
}

msg.measurement = "sensor_health";
msg.tags = {
    sensor_id: data.Serial.toString(),
    gateway_sn: "43250372",
    metric: "battery",
    site: "Cement_Plant"
};
msg.timestamp = new Date(data.Time + "Z").getTime();
msg.payload = {
    battery_pct: data.Batt || 0,
    reading_id: data.ID || 0
};

msg.payload = [msg.payload, msg.tags];
return msg;

// Sensor Heartbeat / Check-in
// Topic: proc/checkin/notify

const data = msg.payload;
if (!data.Serial) {
    node.warn("proc/checkin/notify: Missing 'Serial'");
    return null;
}

msg.measurement = "sensor_health";
msg.tags = {
    sensor_id: data.Serial.toString(),
    gateway_sn: "43250372",
    metric: "checkin",
    site: "Cement_Plant"
};
msg.timestamp = new Date(data.Time + "Z").getTime();
msg.payload = {
    online: 1
};

msg.payload = [msg.payload, msg.tags];
return msg;

// BLE Signal Strength
// Topic: rssi/notify

const data = msg.payload;
if (!data.Serial) {
    node.warn("rssi/notify: Missing 'Serial'");
    return null;
}

msg.measurement = "sensor_health";
msg.tags = {
    sensor_id: data.Serial.toString(),
    gateway_sn: "43250372",
    metric: "rssi",
    site: "Cement_Plant"
};
msg.timestamp = new Date(data.Timestamp + "Z").getTime();
msg.payload = {
    rssi_dbm: data.Rssi || 0
};

msg.payload = [msg.payload, msg.tags];
return msg;

// Error Notifications
// Topic: error/notify

const data = msg.payload;

msg.measurement = "gateway_events";
msg.tags = {
    gateway_sn: "43250372",
    event_type: "error",
    site: "Cement_Plant"
};
msg.timestamp = Date.now();
msg.payload = {
    error_payload: JSON.stringify(data),
    severity: 1
};

node.warn("CTC Gateway ERROR: " + JSON.stringify(data));
msg.payload = [msg.payload, msg.tags];
return msg;

// Status Notifications
// Topic: status/notify

const data = msg.payload;

msg.measurement = "gateway_events";
msg.tags = {
    gateway_sn: "43250372",
    event_type: "status",
    site: "Cement_Plant"
};
msg.timestamp = Date.now();
msg.payload = {
    status_payload: JSON.stringify(data)
};

msg.payload = [msg.payload, msg.tags];
return msg;
